def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    skewness = np.mean((positive_bins - avg_capacity)**3) / (variance ** 1.5 + 1e-9)
    kurtosis = np.mean((positive_bins - avg_capacity)**4) / (variance**2 + 1e-9)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio)**6 * 1.5 + 0.3
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-ratio * 20) + 0.06
        elif 0.4 < ratio <= 0.7:
            temp = 0.0
            for k in range(1, 12):
                sign = (-1)**(k+1)
                term = sign * (ratio ** (k + 3)) / (k * 1.05)
                temp += term
            score = abs(temp) + 0.07
        else:
            temp = 0.0
            for p in range(1, 15):
                weight = 1 / (p ** 1.5)
                temp += ((-1) ** p) * (ratio ** (p + 2)) * weight
            score = abs(temp) + 0.1
        neighbors_influence = 0.0
        neighbors_weight_sum = 0.0
        for offset in range(1, 10):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 2.2 + 0.3)
                    influence = norm_diff * weight
                    if neighbor_capacity > avg_capacity + variance:
                        influence *= 1.15
                    elif neighbor_capacity < avg_capacity - variance:
                        influence *= 0.85
                    neighbors_influence += influence
                    neighbors_weight_sum += weight
        if neighbors_weight_sum > 0:
            neighbors_influence /= neighbors_weight_sum
        else:
            neighbors_influence = 0
        cap_factor = (capacity ** 0.75) + (avg_capacity ** 0.25)
        if cap_factor == 0:
            cap_factor = 1
        penalty = 0
        if capacity < item:
            penalty = ((item - capacity) ** 3.5) * 0.5
        elif capacity > item * 2.5:
            penalty = 0.07
        complexity_adjust = 0
        if skewness > 0.5:
            complexity_adjust += 0.03 * np.sin(ratio * np.pi * 3)
        if kurtosis > 3:
            complexity_adjust += 0.02 * np.cos(ratio * np.pi * 4)
        if i % 5 == 0:
            score *= 0.85
            neighbors_influence *= 1.3
            penalty *= 1.2
            complexity_adjust *= 1.1
        elif i % 3 == 0:
            score *= 1.05
            neighbors_influence *= 0.95
            penalty *= 0.9
        else:
            score *= 0.9
            complexity_adjust *= 0.95
        priority = score + neighbors_influence / cap_factor + penalty + complexity_adjust
        if priority < 0:
            priority = 0
        if priority > 10:
            priority = 10
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]) or priorities[i] == np.inf:
            priorities[i] = max_finite * 5 + (i % 3) * 0.01
    for i in range(n):
        if i > 0 and np.isfinite(priorities[i]) and np.isfinite(priorities[i-1]):
            if abs(priorities[i] - priorities[i-1]) > 2:
                priorities[i] = (priorities[i] + priorities[i-1]) / 2
    sorted_indices = np.argsort(priorities)
    top3_indices = sorted_indices[:3]
    for idx in top3_indices:
        priorities[idx] *= 0.8
    return priorities
